@page "/privacy"
@attribute [Microsoft.AspNetCore.Components.RenderModeAttribute(typeof(NoInteractiveRenderMode))]
@using Microsoft.AspNetCore.Http
@inject IHttpContextAccessor HttpContextAccessor

<PageTitle>Privacy Policy</PageTitle>

<h1>Privacy Policy</h1>

<p>
    This application respects your privacy. We only collect information that is
    necessary to provide our services.
</p>

<h2>Cookie Consent</h2>

@if (HasConsented)
{
    <div class="alert alert-success">
        ✅ You have already accepted our cookie policy.
    </div>
}
else
{
    <div class="alert alert-warning">
        ⚠️ You have not yet accepted our cookie policy.
    </div>
}

<h2>What We Collect</h2>
<ul>
    <li>Essential cookies required for the application to function.</li>
    <li>Optional analytics cookies (only with your consent).</li>
</ul>

<h2>Your Rights</h2>
<p>
    You may withdraw your cookie consent at any time by clearing your browser cookies.
</p>

@code {
    private bool HasConsented { get; set; }

    protected override void OnInitialized()
    {
        var httpContext = HttpContextAccessor.HttpContext;
        if (httpContext is not null)
        {
            HasConsented = httpContext.Request.Cookies.ContainsKey("consent");
        }
    }
}

using Microsoft.AspNetCore.Components;
using Microsoft.AspNetCore.Components.Web;

namespace Components.Pages;

/// <summary>
/// A marker render mode that signals the page should not use interactive rendering.
/// Used by App.razor to conditionally omit the interactive render mode on specific pages.
/// </summary>
public class NoInteractiveRenderMode : IComponentRenderMode
{
}

