<html lang="en">

<head>
    <meta charset="utf-8" />
    <meta name="viewport" content="width=device-width, initial-scale=1.0" />
    <base href="/" />
    <HeadOutlet @rendermode="PageRenderMode" />
</head>

<body>
    <Routes @rendermode="PageRenderMode" />

    <script src="_framework/blazor.web.js"></script>
</body>

</html>

@code {
    [CascadingParameter]
    private HttpContext? HttpContext { get; set; }

    private IComponentRenderMode? PageRenderMode =>
        AssignedRenderMode is Components.Pages.NoInteractiveRenderMode
            ? null
            : new InteractiveServerRenderMode();

    private IComponentRenderMode? AssignedRenderMode
    {
        get
        {
            var endpoint = HttpContext?.GetEndpoint();
            var attribute = endpoint?.Metadata.GetMetadata<RenderModeAttribute>();
            return attribute?.Mode;
        }
    }
}
"}

